def cmd_create_topic(admin: KafkaAdminClient, args: argparse.Namespace) -> int:
    topic_configs = parse_json_or_kv(args.config_json, args.config)
    topic = NewTopic(
        name=args.topic,
        num_partitions=args.partitions,
        replication_factor=args.replication_factor,
        topic_configs=topic_configs or None,
    )
    admin.create_topics(
        new_topics=[topic],
        timeout_ms=args.timeout_ms,
        validate_only=args.validate_only,
    )
    print(json.dumps({
        "status": "ok",
        "action": "create-topic",
        "topic": args.topic,
        "partitions": args.partitions,
        "replication_factor": args.replication_factor,
        "configs": topic_configs,
        "validate_only": args.validate_only,
    }))
    return 0


def cmd_create_topics(admin: KafkaAdminClient, args: argparse.Namespace) -> int:
    with open(args.file, "r", encoding="utf-8") as f:
        payload = json.load(f)

    if not isinstance(payload, list):
        raise ValueError("Topics file must contain a JSON array")

    topics = []
    result_topics = []

    for item in payload:
        if not isinstance(item, dict):
            raise ValueError("Each topic definition must be an object")
        name = item["name"]
        partitions = int(item["partitions"])
        replication_factor = int(item["replication_factor"])
        configs = item.get("configs") or {}
        if not isinstance(configs, dict):
            raise ValueError(f"configs for topic {name} must be an object")
        configs = {str(k): str(v) for k, v in configs.items()}
        topics.append(
            NewTopic(
                name=name,
                num_partitions=partitions,
                replication_factor=replication_factor,
                topic_configs=configs or None,
            )
        )
        result_topics.append({
            "name": name,
            "partitions": partitions,
            "replication_factor": replication_factor,
            "configs": configs,
        })

    admin.create_topics(
        new_topics=topics,
        timeout_ms=args.timeout_ms,
        validate_only=args.validate_only,
    )
    print(json.dumps({
        "status": "ok",
        "action": "create-topics",
        "topics": result_topics,
        "validate_only": args.validate_only,
    }))
    return 0


